// client/src/components/Navbar.js
import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { HomeIcon, MapIcon, PawIcon, CompassIcon, ChecklistIcon } from './Icons';

const Navbar = () => {
  const location = useLocation();

  // Проверка активной вкладки
  const isActive = (path) => {
    return location.pathname === path;
  };

  return (
    <nav className="navbar">
      <Link to="/" className={`nav-item ${isActive('/') ? 'active' : ''}`}>
        <HomeIcon className="nav-icon" />
        <span className="text-xs">Главная</span>
      </Link>

      <Link to="/village" className={`nav-item ${isActive('/village') ? 'active' : ''}`}>
        <MapIcon className="nav-icon" />
        <span className="text-xs">Поселение</span>
      </Link>

      <Link to="/cats" className={`nav-item ${isActive('/cats') ? 'active' : ''}`}>
        <PawIcon className="nav-icon" />
        <span className="text-xs">Кошки</span>
      </Link>

      <Link to="/explore" className={`nav-item ${isActive('/explore') ? 'active' : ''}`}>
        <CompassIcon className="nav-icon" />
        <span className="text-xs">Исследовать</span>
      </Link>

      <Link to="/tasks" className={`nav-item ${isActive('/tasks') ? 'active' : ''}`}>
        <ChecklistIcon className="nav-icon" />
        <span className="text-xs">Задачи</span>
      </Link>
    </nav>
  );
};

export default Navbar;
